-- Corpus conversacional inicial para IA Nivel 1 - Mesa de Ayuda de Calidad
-- Ajustar nombres de columnas si tu tabla dt_ai_knowledge_base usa otra estructura.

create table if not exists dt_ai_training_conversations (
  id text primary key, category text, intent text, user_message text, assistant_message text, keywords text[], learning_rule text, status text default 'active', created_at timestamp default now()
);


-- Vista simple para revisar cobertura por categoría e intención.
create or replace view vw_ai_training_coverage as select category, intent, count(*) total from dt_ai_training_conversations group by category, intent order by category, intent;
