insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0035', 'Conversaciones del área', 'clasificar_area', '¿Esto lo debe revisar Logística?', 'Si el caso está relacionado con entregas, alistamientos, inventarios, despachos, tiempos operativos y novedades de bodega, puede clasificarse para el área de Logística. Si el impacto cruza varias áreas, conviene radicarlo con área principal y mencionar las áreas relacionadas.', ARRAY['logística','área','clasificar','responsable'], 'La IA debe ayudar a clasificar sin inventar responsables.', 'active') on conflict (id) do nothing;
