insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0039', 'Conversaciones del área', 'clasificar_area', '¿Esto lo debe revisar Administrativa?', 'Si el caso está relacionado con documentos, compras, archivo, comunicaciones internas y gestión de recursos, puede clasificarse para el área de Administrativa. Si el impacto cruza varias áreas, conviene radicarlo con área principal y mencionar las áreas relacionadas.', ARRAY['administrativa','área','clasificar','responsable'], 'La IA debe ayudar a clasificar sin inventar responsables.', 'active') on conflict (id) do nothing;
