insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0043', 'Conversaciones del área', 'clasificar_area', '¿Esto lo debe revisar Financiera?', 'Si el caso está relacionado con pagos, facturación, soportes contables, cartera y validaciones económicas, puede clasificarse para el área de Financiera. Si el impacto cruza varias áreas, conviene radicarlo con área principal y mencionar las áreas relacionadas.', ARRAY['financiera','área','clasificar','responsable'], 'La IA debe ayudar a clasificar sin inventar responsables.', 'active') on conflict (id) do nothing;
