insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0045', 'Conversaciones del área', 'crear_ticket_area', 'Necesito radicar una solicitud para Financiera', 'Para radicarla en Financiera, registra una descripción clara, selecciona el área correspondiente, define prioridad, adjunta evidencia si aplica y confirma el solicitante. Si el caso afecta calidad, incluye el impacto o riesgo observado.', ARRAY['financiera','radicar','solicitud','prioridad'], 'Radicación debe pedir datos mínimos.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0046', 'Conversaciones del área', 'resumen_area', 'Dame un resumen de lo pendiente de Financiera', 'Puedo generar el resumen consultando los tickets abiertos, vencidos, en espera y cerrados del área de Financiera. Para hacerlo correctamente necesito acceso a los datos o filtros de fecha definidos.', ARRAY['financiera','resumen','pendiente','tickets'], 'Distinguir conversación de consulta real.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0047', 'Conversaciones del área', 'clasificar_area', '¿Esto lo debe revisar Comercial?', 'Si el caso está relacionado con clientes, solicitudes comerciales, cotizaciones, proyectos y seguimiento a requerimientos externos, puede clasificarse para el área de Comercial. Si el impacto cruza varias áreas, conviene radicarlo con área principal y mencionar las áreas relacionadas.', ARRAY['comercial','área','clasificar','responsable'], 'La IA debe ayudar a clasificar sin inventar responsables.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0048', 'Conversaciones del área', 'consultar_responsable_area', '¿Quién responde los casos de Comercial?', 'La respuesta depende de los usuarios configurados en la aplicación. Puedo consultar el responsable si existe en la base de datos. Si no hay responsable asignado, el caso debe escalarse al jefe general o al Super Admin para configuración.', ARRAY['comercial','responsable','asignado','usuarios'], 'Consultar datos reales si existen.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0049', 'Conversaciones del área', 'crear_ticket_area', 'Necesito radicar una solicitud para Comercial', 'Para radicarla en Comercial, registra una descripción clara, selecciona el área correspondiente, define prioridad, adjunta evidencia si aplica y confirma el solicitante. Si el caso afecta calidad, incluye el impacto o riesgo observado.', ARRAY['comercial','radicar','solicitud','prioridad'], 'Radicación debe pedir datos mínimos.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0050', 'Conversaciones del área', 'resumen_area', 'Dame un resumen de lo pendiente de Comercial', 'Puedo generar el resumen consultando los tickets abiertos, vencidos, en espera y cerrados del área de Comercial. Para hacerlo correctamente necesito acceso a los datos o filtros de fecha definidos.', ARRAY['comercial','resumen','pendiente','tickets'], 'Distinguir conversación de consulta real.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0051', 'Conversaciones del área', 'clasificar_area', '¿Esto lo debe revisar Gerencia?', 'Si el caso está relacionado con decisiones, aprobaciones, escalamiento final y prioridades estratégicas, puede clasificarse para el área de Gerencia. Si el impacto cruza varias áreas, conviene radicarlo con área principal y mencionar las áreas relacionadas.', ARRAY['gerencia','área','clasificar','responsable'], 'La IA debe ayudar a clasificar sin inventar responsables.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0052', 'Conversaciones del área', 'consultar_responsable_area', '¿Quién responde los casos de Gerencia?', 'La respuesta depende de los usuarios configurados en la aplicación. Puedo consultar el responsable si existe en la base de datos. Si no hay responsable asignado, el caso debe escalarse al jefe general o al Super Admin para configuración.', ARRAY['gerencia','responsable','asignado','usuarios'], 'Consultar datos reales si existen.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0053', 'Conversaciones del área', 'crear_ticket_area', 'Necesito radicar una solicitud para Gerencia', 'Para radicarla en Gerencia, registra una descripción clara, selecciona el área correspondiente, define prioridad, adjunta evidencia si aplica y confirma el solicitante. Si el caso afecta calidad, incluye el impacto o riesgo observado.', ARRAY['gerencia','radicar','solicitud','prioridad'], 'Radicación debe pedir datos mínimos.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0054', 'Conversaciones del área', 'resumen_area', 'Dame un resumen de lo pendiente de Gerencia', 'Puedo generar el resumen consultando los tickets abiertos, vencidos, en espera y cerrados del área de Gerencia. Para hacerlo correctamente necesito acceso a los datos o filtros de fecha definidos.', ARRAY['gerencia','resumen','pendiente','tickets'], 'Distinguir conversación de consulta real.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0055', 'Proceso de calidad', 'registrar_no_conformidad', '¿Cómo manejo un caso de no conformidad?', 'Un caso de no conformidad debe describirse el incumplimiento, evidencia, proceso afectado, impacto y responsable inicial. En la Mesa de Ayuda debe quedar documentado como ticket, con comentarios de seguimiento y evidencia asociada para mantener la trazabilidad.', ARRAY['no conformidad','calidad','proceso','evidencia'], 'La IA debe explicar el criterio de calidad y conectarlo con la mesa de ayuda.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0056', 'Proceso de calidad', 'registrar_no_conformidad', 'Tengo un problema de no conformidad', 'Regístralo con una descripción concreta, indica proceso afectado, adjunta soporte y define el impacto. Si requiere análisis, deja el ticket en revisión hasta completar la validación.', ARRAY['no conformidad','problema','registrar','impacto'], 'Transformar un relato en datos estructurados.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0057', 'Proceso de calidad', 'registrar_no_conformidad', '¿Qué evidencia sirve para no conformidad?', 'Sirve cualquier soporte verificable: documento, captura, acta, correo, foto, formato diligenciado, historial del sistema o comentario técnico. Lo importante es que pruebe el hecho reportado y permita seguimiento.', ARRAY['no conformidad','evidencia','soporte','verificable'], 'Orientar sin aceptar evidencias débiles como definitivas.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0058', 'Proceso de calidad', 'registrar_no_conformidad', 'Redáctame una respuesta para un caso de no conformidad', 'Puedes responder así: Se registra el caso relacionado con no conformidad. Se revisará la evidencia aportada, se validará el impacto en el proceso y se definirá la acción correspondiente con responsable y fecha de seguimiento.', ARRAY['no conformidad','redactar','respuesta','caso'], 'Ofrecer redacción base sin cerrar el caso automáticamente.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0059', 'Proceso de calidad', 'accion_correctiva', '¿Cómo manejo un caso de acción correctiva?', 'Un caso de acción correctiva debe orientarse a eliminar la causa raíz y no solo a corregir el efecto inmediato. En la Mesa de Ayuda debe quedar documentado como ticket, con comentarios de seguimiento y evidencia asociada para mantener la trazabilidad.', ARRAY['acción correctiva','calidad','proceso','evidencia'], 'La IA debe explicar el criterio de calidad y conectarlo con la mesa de ayuda.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0060', 'Proceso de calidad', 'accion_correctiva', 'Tengo un problema de acción correctiva', 'Regístralo con una descripción concreta, indica proceso afectado, adjunta soporte y define el impacto. Si requiere análisis, deja el ticket en revisión hasta completar la validación.', ARRAY['acción correctiva','problema','registrar','impacto'], 'Transformar un relato en datos estructurados.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0061', 'Proceso de calidad', 'accion_correctiva', '¿Qué evidencia sirve para acción correctiva?', 'Sirve cualquier soporte verificable: documento, captura, acta, correo, foto, formato diligenciado, historial del sistema o comentario técnico. Lo importante es que pruebe el hecho reportado y permita seguimiento.', ARRAY['acción correctiva','evidencia','soporte','verificable'], 'Orientar sin aceptar evidencias débiles como definitivas.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0062', 'Proceso de calidad', 'accion_correctiva', 'Redáctame una respuesta para un caso de acción correctiva', 'Puedes responder así: Se registra el caso relacionado con acción correctiva. Se revisará la evidencia aportada, se validará el impacto en el proceso y se definirá la acción correspondiente con responsable y fecha de seguimiento.', ARRAY['acción correctiva','redactar','respuesta','caso'], 'Ofrecer redacción base sin cerrar el caso automáticamente.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0063', 'Proceso de calidad', 'accion_preventiva', '¿Cómo manejo un caso de acción preventiva?', 'Un caso de acción preventiva busca reducir la probabilidad de ocurrencia antes de que el problema se materialice. En la Mesa de Ayuda debe quedar documentado como ticket, con comentarios de seguimiento y evidencia asociada para mantener la trazabilidad.', ARRAY['acción preventiva','calidad','proceso','evidencia'], 'La IA debe explicar el criterio de calidad y conectarlo con la mesa de ayuda.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0064', 'Proceso de calidad', 'accion_preventiva', 'Tengo un problema de acción preventiva', 'Regístralo con una descripción concreta, indica proceso afectado, adjunta soporte y define el impacto. Si requiere análisis, deja el ticket en revisión hasta completar la validación.', ARRAY['acción preventiva','problema','registrar','impacto'], 'Transformar un relato en datos estructurados.', 'active') on conflict (id) do nothing;
