insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0067', 'Proceso de calidad', 'mejora_continua', '¿Cómo manejo un caso de mejora continua?', 'Un caso de mejora continua requiere identificar oportunidad, beneficio esperado, responsable y seguimiento. En la Mesa de Ayuda debe quedar documentado como ticket, con comentarios de seguimiento y evidencia asociada para mantener la trazabilidad.', ARRAY['mejora continua','calidad','proceso','evidencia'], 'La IA debe explicar el criterio de calidad y conectarlo con la mesa de ayuda.', 'active') on conflict (id) do nothing;
