insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0071', 'Proceso de calidad', 'validar_evidencia', '¿Cómo manejo un caso de evidencia?', 'Un caso de evidencia debe ser clara, verificable, fechada y relacionada con el caso. En la Mesa de Ayuda debe quedar documentado como ticket, con comentarios de seguimiento y evidencia asociada para mantener la trazabilidad.', ARRAY['evidencia','calidad','proceso','evidencia'], 'La IA debe explicar el criterio de calidad y conectarlo con la mesa de ayuda.', 'active') on conflict (id) do nothing;
