insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0075', 'Proceso de calidad', 'analisis_causa_raiz', '¿Cómo manejo un caso de causa raíz?', 'Un caso de causa raíz puede analizarse con 5 porqués, Ishikawa o revisión de factores del proceso. En la Mesa de Ayuda debe quedar documentado como ticket, con comentarios de seguimiento y evidencia asociada para mantener la trazabilidad.', ARRAY['causa raíz','calidad','proceso','evidencia'], 'La IA debe explicar el criterio de calidad y conectarlo con la mesa de ayuda.', 'active') on conflict (id) do nothing;
