insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0079', 'Proceso de calidad', 'trazabilidad', '¿Cómo manejo un caso de trazabilidad?', 'Un caso de trazabilidad debe quedar registro de fecha, usuario, acción, comentario y soporte. En la Mesa de Ayuda debe quedar documentado como ticket, con comentarios de seguimiento y evidencia asociada para mantener la trazabilidad.', ARRAY['trazabilidad','calidad','proceso','evidencia'], 'La IA debe explicar el criterio de calidad y conectarlo con la mesa de ayuda.', 'active') on conflict (id) do nothing;
