insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0083', 'Proceso de calidad', 'auditoria', '¿Cómo manejo un caso de auditoría?', 'Un caso de auditoría requiere hallazgo, criterio, evidencia, responsable y plan de acción. En la Mesa de Ayuda debe quedar documentado como ticket, con comentarios de seguimiento y evidencia asociada para mantener la trazabilidad.', ARRAY['auditoría','calidad','proceso','evidencia'], 'La IA debe explicar el criterio de calidad y conectarlo con la mesa de ayuda.', 'active') on conflict (id) do nothing;
