insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0087', 'Proceso de calidad', 'indicador_calidad', '¿Cómo manejo un caso de indicador?', 'Un caso de indicador debe tener fórmula, periodicidad, fuente de datos, meta y responsable. En la Mesa de Ayuda debe quedar documentado como ticket, con comentarios de seguimiento y evidencia asociada para mantener la trazabilidad.', ARRAY['indicador','calidad','proceso','evidencia'], 'La IA debe explicar el criterio de calidad y conectarlo con la mesa de ayuda.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0088', 'Proceso de calidad', 'indicador_calidad', 'Tengo un problema de indicador', 'Regístralo con una descripción concreta, indica proceso afectado, adjunta soporte y define el impacto. Si requiere análisis, deja el ticket en revisión hasta completar la validación.', ARRAY['indicador','problema','registrar','impacto'], 'Transformar un relato en datos estructurados.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0089', 'Proceso de calidad', 'indicador_calidad', '¿Qué evidencia sirve para indicador?', 'Sirve cualquier soporte verificable: documento, captura, acta, correo, foto, formato diligenciado, historial del sistema o comentario técnico. Lo importante es que pruebe el hecho reportado y permita seguimiento.', ARRAY['indicador','evidencia','soporte','verificable'], 'Orientar sin aceptar evidencias débiles como definitivas.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0090', 'Proceso de calidad', 'indicador_calidad', 'Redáctame una respuesta para un caso de indicador', 'Puedes responder así: Se registra el caso relacionado con indicador. Se revisará la evidencia aportada, se validará el impacto en el proceso y se definirá la acción correspondiente con responsable y fecha de seguimiento.', ARRAY['indicador','redactar','respuesta','caso'], 'Ofrecer redacción base sin cerrar el caso automáticamente.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0091', 'Proceso de calidad', 'gestion_riesgo', '¿Cómo manejo un caso de riesgo?', 'Un caso de riesgo debe evaluar probabilidad, impacto, control existente y acción de tratamiento. En la Mesa de Ayuda debe quedar documentado como ticket, con comentarios de seguimiento y evidencia asociada para mantener la trazabilidad.', ARRAY['riesgo','calidad','proceso','evidencia'], 'La IA debe explicar el criterio de calidad y conectarlo con la mesa de ayuda.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0092', 'Proceso de calidad', 'gestion_riesgo', 'Tengo un problema de riesgo', 'Regístralo con una descripción concreta, indica proceso afectado, adjunta soporte y define el impacto. Si requiere análisis, deja el ticket en revisión hasta completar la validación.', ARRAY['riesgo','problema','registrar','impacto'], 'Transformar un relato en datos estructurados.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0093', 'Proceso de calidad', 'gestion_riesgo', '¿Qué evidencia sirve para riesgo?', 'Sirve cualquier soporte verificable: documento, captura, acta, correo, foto, formato diligenciado, historial del sistema o comentario técnico. Lo importante es que pruebe el hecho reportado y permita seguimiento.', ARRAY['riesgo','evidencia','soporte','verificable'], 'Orientar sin aceptar evidencias débiles como definitivas.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0094', 'Proceso de calidad', 'gestion_riesgo', 'Redáctame una respuesta para un caso de riesgo', 'Puedes responder así: Se registra el caso relacionado con riesgo. Se revisará la evidencia aportada, se validará el impacto en el proceso y se definirá la acción correspondiente con responsable y fecha de seguimiento.', ARRAY['riesgo','redactar','respuesta','caso'], 'Ofrecer redacción base sin cerrar el caso automáticamente.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0095', 'Radicación', 'explicar_campo_radicacion', '¿Qué pongo en el campo asunto?', 'El asunto debe resumir el caso en pocas palabras, por ejemplo: Retraso en respuesta de calidad o Solicitud de ajuste documental.', ARRAY['asunto','campo','radicación','solicitud'], 'La IA debe explicar campos de formulario en lenguaje simple.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0096', 'Radicación', 'explicar_campo_radicacion', '¿Qué pongo en el campo descripción?', 'La descripción debe explicar qué ocurrió, dónde ocurrió, desde cuándo, qué impacto tiene y qué resultado se espera.', ARRAY['descripción','campo','radicación','solicitud'], 'La IA debe explicar campos de formulario en lenguaje simple.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0097', 'Radicación', 'explicar_campo_radicacion', '¿Qué pongo en el campo área?', 'El área debe ser la principal responsable del análisis o atención del caso.', ARRAY['área','campo','radicación','solicitud'], 'La IA debe explicar campos de formulario en lenguaje simple.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0098', 'Radicación', 'explicar_campo_radicacion', '¿Qué pongo en el campo prioridad?', 'La prioridad debe definirse según impacto, urgencia, vencimiento, riesgo y afectación del servicio.', ARRAY['prioridad','campo','radicación','solicitud'], 'La IA debe explicar campos de formulario en lenguaje simple.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0099', 'Radicación', 'explicar_campo_radicacion', '¿Qué pongo en el campo evidencia?', 'La evidencia puede ser un archivo, foto, documento, captura o comentario verificable asociado al hecho.', ARRAY['evidencia','campo','radicación','solicitud'], 'La IA debe explicar campos de formulario en lenguaje simple.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0100', 'Radicación', 'explicar_campo_radicacion', '¿Qué pongo en el campo responsable?', 'El responsable se asigna según área, flujo de trabajo, carga y permisos configurados.', ARRAY['responsable','campo','radicación','solicitud'], 'La IA debe explicar campos de formulario en lenguaje simple.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0101', 'Radicación', 'explicar_campo_radicacion', '¿Qué pongo en el campo fecha límite?', 'La fecha límite debe responder a la urgencia y a los acuerdos de servicio definidos.', ARRAY['fecha límite','campo','radicación','solicitud'], 'La IA debe explicar campos de formulario en lenguaje simple.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0102', 'Radicación', 'radicar_solicitud', 'Necesito crear un ticket', 'Para crear un ticket debes registrar asunto, descripción, área, prioridad, solicitante y evidencia si aplica. Después confirma la radicación para que el sistema genere trazabilidad.', ARRAY['necesito','crear','debes','registrar','asunto','descripción','prioridad','solicitante','evidencia','aplica'], 'Convertir dudas de radicación en instrucciones de formulario.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0103', 'Radicación', 'radicar_solicitud', 'No tengo evidencia, ¿puedo radicar?', 'Sí puedes radicar si el caso requiere revisión, pero debes indicar que la evidencia está pendiente o explicar por qué no existe. El cierre no debería realizarse sin soporte suficiente cuando el proceso lo exige.', ARRAY['evidencia','radicar','puedes','requiere','revisión','pero','debes','indicar','está','pendiente'], 'Convertir dudas de radicación en instrucciones de formulario.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0104', 'Radicación', 'radicar_solicitud', 'Me equivoqué al radicar', 'No borres la trazabilidad. Agrega un comentario aclaratorio o solicita corrección al responsable autorizado. Si el error cambia el sentido del caso, puede requerirse reclasificación.', ARRAY['equivoqué','radicar','borres','trazabilidad','agrega','comentario','aclaratorio','solicita','corrección','responsable'], 'Convertir dudas de radicación en instrucciones de formulario.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0105', 'Radicación', 'radicar_solicitud', 'Quiero radicar algo anónimo', 'La Mesa de Ayuda debe conservar trazabilidad. Si se permite reporte reservado, debe configurarse como política del sistema; de lo contrario, el solicitante debe quedar identificado.', ARRAY['quiero','radicar','algo','anónimo','mesa','ayuda','conservar','trazabilidad','permite','reporte'], 'Convertir dudas de radicación en instrucciones de formulario.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0106', 'Radicación', 'radicar_solicitud', 'El caso afecta a varias áreas', 'Radícalo con el área principal responsable y menciona las áreas relacionadas en la descripción. Si el flujo lo permite, se pueden agregar responsables de apoyo.', ARRAY['afecta','varias','áreas','radícalo','principal','responsable','menciona','relacionadas','descripción','flujo'], 'Convertir dudas de radicación en instrucciones de formulario.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0107', 'Radicación', 'radicar_solicitud', 'No sé qué prioridad usar', 'Usa prioridad alta si hay riesgo crítico, vencimiento cercano o afectación a varios usuarios. Usa media si requiere atención programada y baja si es mejora o consulta sin urgencia.', ARRAY['prioridad','usar','alta','riesgo','crítico','vencimiento','cercano','afectación','varios','media'], 'Convertir dudas de radicación en instrucciones de formulario.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0108', 'Radicación', 'radicar_solicitud', '¿Puedo adjuntar varios archivos?', 'Sí, cuando el sistema lo permita. Es recomendable nombrar los archivos de forma clara para facilitar revisión y auditoría.', ARRAY['adjuntar','varios','archivos','sistema','permita','recomendable','nombrar','forma','clara','facilitar'], 'Convertir dudas de radicación en instrucciones de formulario.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0109', 'Radicación', 'radicar_solicitud', '¿Qué pasa después de radicar?', 'El ticket queda registrado, se asigna responsable o área, se genera seguimiento y el usuario puede consultar el estado según sus permisos.', ARRAY['pasa','después','radicar','queda','registrado','asigna','responsable','genera','seguimiento','consultar'], 'Convertir dudas de radicación en instrucciones de formulario.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0110', 'Seguimiento y cierre', 'consultar_estado', '¿En qué estado está mi ticket?', 'Para consultar el estado necesito el número de ticket o identificar la solicitud. Si el sistema encuentra el registro, te indicaré estado actual, responsable y última actualización permitida.', ARRAY['estado','está','consultar','necesito','número','identificar','sistema','encuentra','registro','indicaré'], 'Mantener flujo, trazabilidad y control de permisos.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0111', 'Seguimiento y cierre', 'consultar_ticket', 'Busca el ticket DT-0001', 'Voy a buscar el ticket en la base de datos. Si existe y tienes permiso para verlo, puedo mostrar estado, responsable, prioridad, área y último seguimiento.', ARRAY['busca','0001','buscar','base','datos','existe','permiso','verlo','mostrar','estado'], 'Mantener flujo, trazabilidad y control de permisos.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0112', 'Seguimiento y cierre', 'agregar_comentario', 'Quiero agregar un comentario', 'Puedes agregarlo como seguimiento del ticket. El comentario debe ser claro, relacionado con el caso y conservar trazabilidad. No reemplaza la evidencia cuando esta es obligatoria.', ARRAY['quiero','agregar','comentario','puedes','agregarlo','seguimiento','claro','relacionado','conservar','trazabilidad'], 'Mantener flujo, trazabilidad y control de permisos.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0113', 'Seguimiento y cierre', 'agregar_evidencia', 'Quiero subir una evidencia', 'Adjunta el soporte al ticket y describe qué demuestra. La evidencia debe estar relacionada con la solicitud y ser verificable para auditoría.', ARRAY['quiero','subir','evidencia','adjunta','soporte','describe','demuestra','estar','relacionada','verificable'], 'Mantener flujo, trazabilidad y control de permisos.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0114', 'Seguimiento y cierre', 'cerrar_ticket', '¿Cómo cierro un ticket?', 'Antes de cerrar, valida que exista respuesta final, evidencia suficiente, responsable definido y que el solicitante haya sido informado si aplica. El cierre debe quedar registrado con comentario final.', ARRAY['cómo','cierro','antes','cerrar','valida','exista','respuesta','final','evidencia','suficiente'], 'Mantener flujo, trazabilidad y control de permisos.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0115', 'Seguimiento y cierre', 'reabrir_ticket', 'Necesito reabrir un ticket cerrado', 'La reapertura debe justificarse. Indica por qué el cierre no resolvió el caso, qué evidencia nueva existe o qué actividad quedó pendiente.', ARRAY['necesito','reabrir','cerrado','reapertura','justificarse','indica','cierre','resolvió','evidencia','nueva'], 'Mantener flujo, trazabilidad y control de permisos.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0116', 'Seguimiento y cierre', 'escalar_ticket', 'Este ticket no avanza', 'Si el ticket está detenido, revisa responsable, fecha de última gestión, evidencia y causa de espera. Si supera el tiempo permitido, puede escalarse al jefe general con justificación.', ARRAY['avanza','está','detenido','revisa','responsable','fecha','última','gestión','evidencia','causa'], 'Mantener flujo, trazabilidad y control de permisos.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0117', 'Seguimiento y cierre', 'ampliar_espera', 'Necesito más tiempo para resolver', 'Puedes solicitar ampliación de espera con una causa clara, nueva fecha estimada y comentario de seguimiento. No debe usarse para ocultar inactividad.', ARRAY['necesito','tiempo','resolver','puedes','solicitar','ampliación','espera','causa','clara','nueva'], 'Mantener flujo, trazabilidad y control de permisos.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0118', 'Seguimiento y cierre', 'vencimiento', '¿Qué significa ticket vencido?', 'Un ticket vencido es aquel que superó el tiempo definido sin cierre o sin la acción esperada. Debe revisarse prioridad, responsable y causa del incumplimiento.', ARRAY['significa','vencido','aquel','superó','tiempo','definido','cierre','acción','esperada','revisarse'], 'Mantener flujo, trazabilidad y control de permisos.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0119', 'Seguimiento y cierre', 'satisfaccion', 'El usuario no quedó satisfecho', 'Registra el comentario del usuario, revisa si el cierre fue adecuado y evalúa reapertura, acción correctiva o mejora si el caso revela falla del proceso.', ARRAY['quedó','satisfecho','registra','comentario','revisa','cierre','adecuado','evalúa','reapertura','acción'], 'Mantener flujo, trazabilidad y control de permisos.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0120', 'Seguimiento y cierre', 'consultar_estado', 'Estado de mi solicitud', 'Para consultar eso necesito identificar el ticket. Si lo encuentro y tienes permiso, te mostraré estado, responsable, prioridad y último movimiento.', ARRAY['estado','consultar','necesito','identificar','encuentro','permiso','mostraré','responsable','prioridad','último'], 'Aprender sinónimos operativos del flujo.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0121', 'Seguimiento y cierre', 'consultar_estado', 'Cómo va el caso', 'Para consultar eso necesito identificar el ticket. Si lo encuentro y tienes permiso, te mostraré estado, responsable, prioridad y último movimiento.', ARRAY['cómo','consultar','necesito','identificar','encuentro','permiso','mostraré','estado','responsable','prioridad'], 'Aprender sinónimos operativos del flujo.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0122', 'Seguimiento y cierre', 'consultar_estado', 'Qué pasó con el ticket', 'Para consultar eso necesito identificar el ticket. Si lo encuentro y tienes permiso, te mostraré estado, responsable, prioridad y último movimiento.', ARRAY['pasó','consultar','necesito','identificar','encuentro','permiso','mostraré','estado','responsable','prioridad'], 'Aprender sinónimos operativos del flujo.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0123', 'Seguimiento y cierre', 'consultar_estado', 'En qué va mi requerimiento', 'Para consultar eso necesito identificar el ticket. Si lo encuentro y tienes permiso, te mostraré estado, responsable, prioridad y último movimiento.', ARRAY['requerimiento','consultar','necesito','identificar','encuentro','permiso','mostraré','estado','responsable','prioridad'], 'Aprender sinónimos operativos del flujo.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0124', 'Seguimiento y cierre', 'cerrar_ticket', 'Finalizar el caso', 'Para finalizarlo, verifica evidencia, respuesta final, validación del solicitante si aplica y comentario de cierre. El sistema debe conservar la trazabilidad.', ARRAY['finalizar','finalizarlo','verifica','evidencia','respuesta','final','validación','solicitante','aplica','comentario'], 'Aprender sinónimos operativos del flujo.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0125', 'Seguimiento y cierre', 'cerrar_ticket', 'Dar por terminado el ticket', 'Para finalizarlo, verifica evidencia, respuesta final, validación del solicitante si aplica y comentario de cierre. El sistema debe conservar la trazabilidad.', ARRAY['terminado','finalizarlo','verifica','evidencia','respuesta','final','validación','solicitante','aplica','comentario'], 'Aprender sinónimos operativos del flujo.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0126', 'Seguimiento y cierre', 'cerrar_ticket', 'Marcar como cerrado', 'Para finalizarlo, verifica evidencia, respuesta final, validación del solicitante si aplica y comentario de cierre. El sistema debe conservar la trazabilidad.', ARRAY['marcar','cerrado','finalizarlo','verifica','evidencia','respuesta','final','validación','solicitante','aplica'], 'Aprender sinónimos operativos del flujo.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0127', 'Seguimiento y cierre', 'cerrar_ticket', 'Cerrar la solicitud', 'Para finalizarlo, verifica evidencia, respuesta final, validación del solicitante si aplica y comentario de cierre. El sistema debe conservar la trazabilidad.', ARRAY['cerrar','finalizarlo','verifica','evidencia','respuesta','final','validación','solicitante','aplica','comentario'], 'Aprender sinónimos operativos del flujo.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0128', 'Seguimiento y cierre', 'escalar_ticket', 'Pasarlo al jefe', 'Puedes escalarlo si hay bloqueo, vencimiento o decisión pendiente. Registra la justificación y conserva los comentarios previos del responsable.', ARRAY['pasarlo','jefe','puedes','escalarlo','bloqueo','vencimiento','decisión','pendiente','registra','justificación'], 'Aprender sinónimos operativos del flujo.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0129', 'Seguimiento y cierre', 'escalar_ticket', 'Subir el caso', 'Puedes escalarlo si hay bloqueo, vencimiento o decisión pendiente. Registra la justificación y conserva los comentarios previos del responsable.', ARRAY['subir','puedes','escalarlo','bloqueo','vencimiento','decisión','pendiente','registra','justificación','conserva'], 'Aprender sinónimos operativos del flujo.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0130', 'Seguimiento y cierre', 'escalar_ticket', 'Pedir revisión superior', 'Puedes escalarlo si hay bloqueo, vencimiento o decisión pendiente. Registra la justificación y conserva los comentarios previos del responsable.', ARRAY['pedir','revisión','superior','puedes','escalarlo','bloqueo','vencimiento','decisión','pendiente','registra'], 'Aprender sinónimos operativos del flujo.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0131', 'Seguimiento y cierre', 'escalar_ticket', 'Esto está bloqueado', 'Puedes escalarlo si hay bloqueo, vencimiento o decisión pendiente. Registra la justificación y conserva los comentarios previos del responsable.', ARRAY['está','bloqueado','puedes','escalarlo','bloqueo','vencimiento','decisión','pendiente','registra','justificación'], 'Aprender sinónimos operativos del flujo.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0132', 'Seguimiento y cierre', 'agregar_evidencia', 'Subir soporte', 'Adjunta el soporte al ticket y explica qué prueba. La evidencia debe quedar vinculada al caso para revisión posterior.', ARRAY['subir','soporte','adjunta','explica','prueba','evidencia','quedar','vinculada','revisión','posterior'], 'Aprender sinónimos operativos del flujo.', 'active') on conflict (id) do nothing;
