insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0140', 'Reportes e indicadores', 'consultar_tickets_abiertos', '¿Cómo reviso tickets abiertos?', 'El indicador de tickets abiertos muestra cantidad de casos activos que aún requieren gestión. Puedo consultarlo si el sistema tiene los datos y filtros requeridos, como rango de fechas, área o responsable.', ARRAY['tickets abiertos','indicador','kpi','reporte'], 'Distinguir explicación de KPI y consulta real de datos.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0141', 'Reportes e indicadores', 'consultar_tickets_abiertos', 'Dame un reporte de tickets abiertos', 'Para generar el reporte de tickets abiertos, necesito definir periodo, área y nivel de detalle. El resultado debe mostrar dato principal, tendencia y casos que requieren acción.', ARRAY['tickets abiertos','reporte','periodo','área'], 'Pedir filtros antes de calcular si faltan datos.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0142', 'Reportes e indicadores', 'consultar_tickets_vencidos', '¿Cómo reviso tickets vencidos?', 'El indicador de tickets vencidos muestra casos que superaron el tiempo definido de atención. Puedo consultarlo si el sistema tiene los datos y filtros requeridos, como rango de fechas, área o responsable.', ARRAY['tickets vencidos','indicador','kpi','reporte'], 'Distinguir explicación de KPI y consulta real de datos.', 'active') on conflict (id) do nothing;
