insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0144', 'Reportes e indicadores', 'kpi_tiempo_cierre', '¿Cómo reviso tiempo promedio de cierre?', 'El indicador de tiempo promedio de cierre muestra promedio entre radicación y cierre de tickets. Puedo consultarlo si el sistema tiene los datos y filtros requeridos, como rango de fechas, área o responsable.', ARRAY['tiempo promedio de cierre','indicador','kpi','reporte'], 'Distinguir explicación de KPI y consulta real de datos.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0145', 'Reportes e indicadores', 'kpi_tiempo_cierre', 'Dame un reporte de tiempo promedio de cierre', 'Para generar el reporte de tiempo promedio de cierre, necesito definir periodo, área y nivel de detalle. El resultado debe mostrar dato principal, tendencia y casos que requieren acción.', ARRAY['tiempo promedio de cierre','reporte','periodo','área'], 'Pedir filtros antes de calcular si faltan datos.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0146', 'Reportes e indicadores', 'kpi_area', '¿Cómo reviso casos por área?', 'El indicador de casos por área muestra distribución de solicitudes según área responsable. Puedo consultarlo si el sistema tiene los datos y filtros requeridos, como rango de fechas, área o responsable.', ARRAY['casos por área','indicador','kpi','reporte'], 'Distinguir explicación de KPI y consulta real de datos.', 'active') on conflict (id) do nothing;
