insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0148', 'Reportes e indicadores', 'kpi_reincidencia', '¿Cómo reviso reincidencias?', 'El indicador de reincidencias muestra temas o problemas repetidos en un periodo. Puedo consultarlo si el sistema tiene los datos y filtros requeridos, como rango de fechas, área o responsable.', ARRAY['reincidencias','indicador','kpi','reporte'], 'Distinguir explicación de KPI y consulta real de datos.', 'active') on conflict (id) do nothing;
