insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0150', 'Reportes e indicadores', 'kpi_satisfaccion', '¿Cómo reviso satisfacción?', 'El indicador de satisfacción muestra percepción del solicitante después del cierre. Puedo consultarlo si el sistema tiene los datos y filtros requeridos, como rango de fechas, área o responsable.', ARRAY['satisfacción','indicador','kpi','reporte'], 'Distinguir explicación de KPI y consulta real de datos.', 'active') on conflict (id) do nothing;
