insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0152', 'Reportes e indicadores', 'kpi_mejoras', '¿Cómo reviso mejoras generadas?', 'El indicador de mejoras generadas muestra acciones de mejora derivadas de tickets. Puedo consultarlo si el sistema tiene los datos y filtros requeridos, como rango de fechas, área o responsable.', ARRAY['mejoras generadas','indicador','kpi','reporte'], 'Distinguir explicación de KPI y consulta real de datos.', 'active') on conflict (id) do nothing;
