insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0154', 'Reportes e indicadores', 'kpi_responsable', '¿Cómo reviso carga por responsable?', 'El indicador de carga por responsable muestra cantidad de tickets asignados a cada usuario. Puedo consultarlo si el sistema tiene los datos y filtros requeridos, como rango de fechas, área o responsable.', ARRAY['carga por responsable','indicador','kpi','reporte'], 'Distinguir explicación de KPI y consulta real de datos.', 'active') on conflict (id) do nothing;
