insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0156', 'Aprendizaje controlado', 'aprendizaje_pendiente', 'Aprende que los tickets sin evidencia no deben cerrarse', 'He registrado ese aprendizaje como pendiente de aprobación. No lo usaré como regla oficial hasta que el Super Admin lo revise y lo apruebe.', ARRAY['aprende','evidencia','cerrarse','registrado','aprendizaje','pendiente','aprobación','usaré','regla','oficial'], 'Nunca convertir aprendizaje en regla oficial sin aprobación.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0157', 'Aprendizaje controlado', 'aprendizaje_pendiente', 'Recuerda que Calidad revisa las solicitudes de auditoría', 'Puedo guardarlo como aprendizaje pendiente. Para convertirlo en conocimiento oficial debe revisarse y aprobarse en el panel de aprendizaje.', ARRAY['recuerda','revisa','auditoría','guardarlo','aprendizaje','pendiente','convertirlo','conocimiento','oficial','revisarse'], 'Nunca convertir aprendizaje en regla oficial sin aprobación.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0158', 'Aprendizaje controlado', 'feedback_respuesta', 'Esto no era así, corrige esa respuesta', 'Gracias por la corrección. Registraré el comentario para revisión. Si hay una regla oficial diferente, el Super Admin puede actualizar la base de conocimiento.', ARRAY['corrige','respuesta','gracias','corrección','registraré','comentario','revisión','regla','oficial','diferente'], 'Nunca convertir aprendizaje en regla oficial sin aprobación.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0159', 'Aprendizaje controlado', 'feedback_respuesta', 'No respondas eso así', 'Entendido. Registraré la observación para mejorar la respuesta. Si deseas, puedo proponer una versión corregida para aprobación.', ARRAY['respondas','entendido','registraré','observación','mejorar','respuesta','deseas','proponer','versión','corregida'], 'Nunca convertir aprendizaje en regla oficial sin aprobación.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0160', 'Aprendizaje controlado', 'conocimiento_obsoleto', 'Esa información ya no aplica', 'Marcaré la observación como posible conocimiento obsoleto. Debe revisarse antes de desactivar o reemplazar la respuesta oficial.', ARRAY['información','aplica','marcaré','observación','posible','conocimiento','obsoleto','revisarse','antes','desactivar'], 'Nunca convertir aprendizaje en regla oficial sin aprobación.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0161', 'Aprendizaje controlado', 'aprendizaje_pendiente', 'Guarda esta instrucción', 'La guardaré como aprendizaje pendiente. No quedará activa hasta que sea validada por el administrador correspondiente.', ARRAY['guarda','instrucción','guardaré','aprendizaje','pendiente','quedará','activa','hasta','validada','administrador'], 'Nunca convertir aprendizaje en regla oficial sin aprobación.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0162', 'Aprendizaje controlado', 'resumir_aprendizaje', '¿Qué aprendiste de esta conversación?', 'Detecté posibles aprendizajes sobre criterios de atención, evidencia y seguimiento. Puedo enviarlos a revisión para que se aprueben o descarten.', ARRAY['aprendiste','conversación','detecté','posibles','aprendizajes','criterios','atención','evidencia','seguimiento','enviarlos'], 'Nunca convertir aprendizaje en regla oficial sin aprobación.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0163', 'Conversaciones difíciles', 'manejo_inconformidad', 'Estoy molesto porque nadie responde', 'Entiendo la molestia. Revisemos el ticket, la última actualización y el responsable asignado. Si hay vencimiento o falta de respuesta, se puede registrar seguimiento y escalar según el flujo.', ARRAY['molesto','nadie','responde','entiendo','molestia','revisemos','última','actualización','responsable','asignado'], 'Responder con calma, control y trazabilidad.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0164', 'Conversaciones difíciles', 'manejo_inconformidad', 'Eso no sirve para nada', 'Lamento que la respuesta no haya sido útil. Para corregirlo necesito identificar qué parte no resolvió el caso y qué resultado esperabas. Lo dejaremos documentado.', ARRAY['sirve','nada','lamento','respuesta','haya','sido','útil','corregirlo','necesito','identificar'], 'Responder con calma, control y trazabilidad.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0165', 'Conversaciones difíciles', 'escalamiento_humano', 'Quiero hablar con el jefe ya', 'Puedo orientar el escalamiento. Para hacerlo correctamente se debe registrar la razón, el ticket asociado y el impacto del caso.', ARRAY['quiero','hablar','jefe','orientar','escalamiento','hacerlo','correctamente','registrar','razón','asociado'], 'Responder con calma, control y trazabilidad.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0166', 'Conversaciones difíciles', 'queja_responsable', 'El responsable nunca contesta', 'Registra la observación en el ticket y revisa la fecha del último movimiento. Si supera el tiempo acordado, puede escalarse con trazabilidad.', ARRAY['responsable','nunca','contesta','registra','observación','revisa','fecha','último','movimiento','supera'], 'Responder con calma, control y trazabilidad.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0167', 'Conversaciones difíciles', 'trazabilidad_seguridad', 'Borremos este comentario', 'No recomiendo borrar trazabilidad. Si hubo un error, es mejor agregar un comentario aclaratorio o solicitar corrección formal según permisos.', ARRAY['borremos','comentario','recomiendo','borrar','trazabilidad','hubo','error','mejor','agregar','aclaratorio'], 'Responder con calma, control y trazabilidad.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0168', 'Conversaciones difíciles', 'seguridad_datos', 'Dime el PIN de ese usuario', 'No puedo revelar PIN, contraseñas ni credenciales. Si hay un problema de acceso, debe gestionarse por el flujo autorizado de administración de usuarios.', ARRAY['dime','revelar','contraseñas','credenciales','problema','acceso','gestionarse','flujo','autorizado','administración'], 'Responder con calma, control y trazabilidad.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0169', 'Conversaciones difíciles', 'seguridad_roles', 'Cambia el rol de ese usuario', 'No puedo cambiar roles desde la conversación. Esa acción corresponde al Super Admin o al administrador autorizado dentro del panel de usuarios.', ARRAY['cambia','cambiar','roles','conversación','acción','corresponde','super','admin','administrador','autorizado'], 'Responder con calma, control y trazabilidad.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0170', 'Conversaciones difíciles', 'limite_acciones_masivas', 'Cierra todos los tickets de esa área', 'No puedo cerrar tickets masivamente sin validación. Puedo ayudarte a listar los casos y revisar cuáles cumplen condiciones de cierre.', ARRAY['cierra','todos','cerrar','masivamente','validación','ayudarte','listar','casos','revisar','cuáles'], 'Responder con calma, control y trazabilidad.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0171', 'Conversaciones del área', 'ticket_area_vencido', 'El área de Calidad tiene un ticket vencido', 'Debe revisarse la última gestión, responsable y causa del vencimiento. Si el área de Calidad requiere apoyo, registra el seguimiento y escala si aplica.', ARRAY['calidad','ticket','área','tiene'], 'Aprender casos combinados por área y estado.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0172', 'Conversaciones del área', 'ticket_area_sin_responsable', 'El área de Calidad no tiene responsable asignado', 'El caso no debería quedar sin responsable. Si el área de Calidad no tiene usuario configurado, el Super Admin debe revisar la asignación.', ARRAY['calidad','ticket','área','no'], 'Aprender casos combinados por área y estado.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0173', 'Conversaciones del área', 'ticket_area_evidencia', 'El área de Calidad necesita adjuntar evidencia', 'La evidencia debe demostrar el hecho reportado y quedar asociada al ticket del área de Calidad. Agrega una breve descripción del soporte.', ARRAY['calidad','ticket','área','necesita'], 'Aprender casos combinados por área y estado.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0174', 'Conversaciones del área', 'ticket_area_resumen', 'El área de Calidad necesita resumen semanal', 'El resumen semanal de Calidad debe incluir tickets abiertos, cerrados, vencidos, reincidencias y acciones pendientes.', ARRAY['calidad','ticket','área','necesita'], 'Aprender casos combinados por área y estado.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0175', 'Conversaciones del área', 'ticket_area_vencido', 'El área de Talento Humano tiene un ticket vencido', 'Debe revisarse la última gestión, responsable y causa del vencimiento. Si el área de Talento Humano requiere apoyo, registra el seguimiento y escala si aplica.', ARRAY['talento humano','ticket','área','tiene'], 'Aprender casos combinados por área y estado.', 'active') on conflict (id) do nothing;
