insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0203', 'Proceso de calidad', 'etapa_proceso_calidad', 'Explícame la etapa de identificación del problema', 'Describe el hecho sin juicios personales, indicando fecha, área, evidencia y efecto observado. En la Mesa de Ayuda se debe registrar cada avance como comentario o actualización del ticket.', ARRAY['identificación del problema','proceso','calidad','etapa'], 'Entrenar explicación de etapas del flujo de calidad.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0204', 'Proceso de calidad', 'etapa_proceso_calidad', '¿Qué reviso en identificación del problema?', 'Describe el hecho sin juicios personales, indicando fecha, área, evidencia y efecto observado.', ARRAY['identificación del problema','revisar','calidad'], 'Convertir etapas en listas de verificación.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0205', 'Proceso de calidad', 'etapa_proceso_calidad', 'Explícame la etapa de análisis inicial', 'Revisa si el caso tiene evidencia suficiente, área responsable, prioridad correcta y posible impacto en el proceso. En la Mesa de Ayuda se debe registrar cada avance como comentario o actualización del ticket.', ARRAY['análisis inicial','proceso','calidad','etapa'], 'Entrenar explicación de etapas del flujo de calidad.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0206', 'Proceso de calidad', 'etapa_proceso_calidad', '¿Qué reviso en análisis inicial?', 'Revisa si el caso tiene evidencia suficiente, área responsable, prioridad correcta y posible impacto en el proceso.', ARRAY['análisis inicial','revisar','calidad'], 'Convertir etapas en listas de verificación.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0207', 'Proceso de calidad', 'etapa_proceso_calidad', 'Explícame la etapa de asignación de responsable', 'El responsable debe tener competencia y permiso para atender el caso; si no existe, se escala para configuración. En la Mesa de Ayuda se debe registrar cada avance como comentario o actualización del ticket.', ARRAY['asignación de responsable','proceso','calidad','etapa'], 'Entrenar explicación de etapas del flujo de calidad.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0208', 'Proceso de calidad', 'etapa_proceso_calidad', '¿Qué reviso en asignación de responsable?', 'El responsable debe tener competencia y permiso para atender el caso; si no existe, se escala para configuración.', ARRAY['asignación de responsable','revisar','calidad'], 'Convertir etapas en listas de verificación.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0209', 'Proceso de calidad', 'etapa_proceso_calidad', 'Explícame la etapa de plan de acción', 'Debe incluir actividad, responsable, fecha, evidencia esperada y criterio de cierre. En la Mesa de Ayuda se debe registrar cada avance como comentario o actualización del ticket.', ARRAY['plan de acción','proceso','calidad','etapa'], 'Entrenar explicación de etapas del flujo de calidad.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0210', 'Proceso de calidad', 'etapa_proceso_calidad', '¿Qué reviso en plan de acción?', 'Debe incluir actividad, responsable, fecha, evidencia esperada y criterio de cierre.', ARRAY['plan de acción','revisar','calidad'], 'Convertir etapas en listas de verificación.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0211', 'Proceso de calidad', 'etapa_proceso_calidad', 'Explícame la etapa de verificación de eficacia', 'No basta con ejecutar la acción; se debe validar si resolvió la causa o redujo la recurrencia. En la Mesa de Ayuda se debe registrar cada avance como comentario o actualización del ticket.', ARRAY['verificación de eficacia','proceso','calidad','etapa'], 'Entrenar explicación de etapas del flujo de calidad.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0212', 'Proceso de calidad', 'etapa_proceso_calidad', '¿Qué reviso en verificación de eficacia?', 'No basta con ejecutar la acción; se debe validar si resolvió la causa o redujo la recurrencia.', ARRAY['verificación de eficacia','revisar','calidad'], 'Convertir etapas en listas de verificación.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0213', 'Proceso de calidad', 'etapa_proceso_calidad', 'Explícame la etapa de cierre documental', 'El cierre debe dejar respuesta final, evidencia, conclusión y trazabilidad completa. En la Mesa de Ayuda se debe registrar cada avance como comentario o actualización del ticket.', ARRAY['cierre documental','proceso','calidad','etapa'], 'Entrenar explicación de etapas del flujo de calidad.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0214', 'Proceso de calidad', 'etapa_proceso_calidad', '¿Qué reviso en cierre documental?', 'El cierre debe dejar respuesta final, evidencia, conclusión y trazabilidad completa.', ARRAY['cierre documental','revisar','calidad'], 'Convertir etapas en listas de verificación.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0215', 'Radicación', 'radicar_solicitud_especifica', 'Necesito radicar una queja interna', 'Registra la queja con descripción objetiva, área involucrada, evidencia si existe, impacto y datos del solicitante. Evita lenguaje ofensivo y conserva trazabilidad.', ARRAY['radicar','queja','interna','registra','descripción','objetiva','involucrada','evidencia','existe','impacto'], 'Entrenar radicación por tipo de solicitud.', 'active') on conflict (id) do nothing;
