insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0231', 'Radicación', 'detectar_error_radicacion', 'El ticket tiene descripción muy corta', 'Pide ampliar contexto: qué ocurrió, cuándo, dónde, impacto y evidencia. Esto ayuda a mantener calidad de datos y trazabilidad.', ARRAY['descripción muy corta','error','radicación','ticket'], 'Detectar errores comunes de radicación.', 'active') on conflict (id) do nothing;
