insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0235', 'Radicación', 'detectar_error_radicacion', 'El ticket tiene prioridad inflada', 'Pide justificar urgencia con impacto, vencimiento o riesgo real. Esto ayuda a mantener calidad de datos y trazabilidad.', ARRAY['prioridad inflada','error','radicación','ticket'], 'Detectar errores comunes de radicación.', 'active') on conflict (id) do nothing;
