insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0237', 'Radicación', 'detectar_error_radicacion', 'El ticket tiene sin evidencia', 'Permite radicación, pero marca evidencia pendiente si el cierre exige soporte. Esto ayuda a mantener calidad de datos y trazabilidad.', ARRAY['sin evidencia','error','radicación','ticket'], 'Detectar errores comunes de radicación.', 'active') on conflict (id) do nothing;
