insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0239', 'Radicación', 'detectar_error_radicacion', 'El ticket tiene ticket duplicado', 'Sugiere buscar casos similares y relacionar el nuevo comentario al ticket existente. Esto ayuda a mantener calidad de datos y trazabilidad.', ARRAY['ticket duplicado','error','radicación','ticket'], 'Detectar errores comunes de radicación.', 'active') on conflict (id) do nothing;
