insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0241', 'Radicación', 'detectar_error_radicacion', 'El ticket tiene cierre sin respuesta final', 'Indica que debe agregarse respuesta final antes del cierre. Esto ayuda a mantener calidad de datos y trazabilidad.', ARRAY['cierre sin respuesta final','error','radicación','ticket'], 'Detectar errores comunes de radicación.', 'active') on conflict (id) do nothing;
