insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0243', 'Radicación', 'detectar_error_radicacion', 'El ticket tiene comentarios desordenados', 'Sugiere resumir estado actual y próximo paso en un comentario claro. Esto ayuda a mantener calidad de datos y trazabilidad.', ARRAY['comentarios desordenados','error','radicación','ticket'], 'Detectar errores comunes de radicación.', 'active') on conflict (id) do nothing;
