insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0245', 'Seguimiento y cierre', 'explicar_estado_ticket', '¿Qué significa estado abierto?', 'El caso fue creado y aún requiere gestión. La interpretación final depende del flujo configurado en la app.', ARRAY['abierto','estado','ticket'], 'Entrenar explicación de estados.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0246', 'Seguimiento y cierre', 'explicar_estado_ticket', 'Mi solicitud aparece como abierto', 'El caso fue creado y aún requiere gestión. Revisa el último comentario para conocer el siguiente paso.', ARRAY['abierto','solicitud','estado'], 'Responder desde la perspectiva del usuario.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0247', 'Seguimiento y cierre', 'explicar_estado_ticket', '¿Qué significa estado asignado?', 'Ya existe un responsable definido para atenderlo. La interpretación final depende del flujo configurado en la app.', ARRAY['asignado','estado','ticket'], 'Entrenar explicación de estados.', 'active') on conflict (id) do nothing;
