insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0249', 'Seguimiento y cierre', 'explicar_estado_ticket', '¿Qué significa estado en revisión?', 'El responsable está validando información, evidencia o impacto. La interpretación final depende del flujo configurado en la app.', ARRAY['en revisión','estado','ticket'], 'Entrenar explicación de estados.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0250', 'Seguimiento y cierre', 'explicar_estado_ticket', 'Mi solicitud aparece como en revisión', 'El responsable está validando información, evidencia o impacto. Revisa el último comentario para conocer el siguiente paso.', ARRAY['en revisión','solicitud','estado'], 'Responder desde la perspectiva del usuario.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0251', 'Seguimiento y cierre', 'explicar_estado_ticket', '¿Qué significa estado en espera?', 'El caso depende de información, autorización o evidencia adicional. La interpretación final depende del flujo configurado en la app.', ARRAY['en espera','estado','ticket'], 'Entrenar explicación de estados.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0252', 'Seguimiento y cierre', 'explicar_estado_ticket', 'Mi solicitud aparece como en espera', 'El caso depende de información, autorización o evidencia adicional. Revisa el último comentario para conocer el siguiente paso.', ARRAY['en espera','solicitud','estado'], 'Responder desde la perspectiva del usuario.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0253', 'Seguimiento y cierre', 'explicar_estado_ticket', '¿Qué significa estado vencido?', 'El tiempo esperado fue superado y requiere revisión prioritaria. La interpretación final depende del flujo configurado en la app.', ARRAY['vencido','estado','ticket'], 'Entrenar explicación de estados.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0254', 'Seguimiento y cierre', 'explicar_estado_ticket', 'Mi solicitud aparece como vencido', 'El tiempo esperado fue superado y requiere revisión prioritaria. Revisa el último comentario para conocer el siguiente paso.', ARRAY['vencido','solicitud','estado'], 'Responder desde la perspectiva del usuario.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0255', 'Seguimiento y cierre', 'explicar_estado_ticket', '¿Qué significa estado cerrado?', 'El caso tiene conclusión registrada y no requiere acciones activas. La interpretación final depende del flujo configurado en la app.', ARRAY['cerrado','estado','ticket'], 'Entrenar explicación de estados.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0256', 'Seguimiento y cierre', 'explicar_estado_ticket', 'Mi solicitud aparece como cerrado', 'El caso tiene conclusión registrada y no requiere acciones activas. Revisa el último comentario para conocer el siguiente paso.', ARRAY['cerrado','solicitud','estado'], 'Responder desde la perspectiva del usuario.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0257', 'Seguimiento y cierre', 'explicar_estado_ticket', '¿Qué significa estado reabierto?', 'El cierre anterior no resolvió completamente el caso o apareció evidencia nueva. La interpretación final depende del flujo configurado en la app.', ARRAY['reabierto','estado','ticket'], 'Entrenar explicación de estados.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0258', 'Seguimiento y cierre', 'explicar_estado_ticket', 'Mi solicitud aparece como reabierto', 'El cierre anterior no resolvió completamente el caso o apareció evidencia nueva. Revisa el último comentario para conocer el siguiente paso.', ARRAY['reabierto','solicitud','estado'], 'Responder desde la perspectiva del usuario.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0259', 'Proceso de calidad', 'diferenciar_acciones_calidad', '¿Qué diferencia hay entre corrección y otras acciones?', 'Corrección: Soluciona el efecto inmediato del problema. En la Mesa de Ayuda debe quedar claro si se trata de contención, corrección, acción correctiva, preventiva o mejora.', ARRAY['corrección','acción','calidad','diferencia'], 'Enseñar diferencias de gestión de calidad.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0260', 'Proceso de calidad', 'diferenciar_acciones_calidad', '¿Qué diferencia hay entre acción correctiva y otras acciones?', 'Acción correctiva: Busca eliminar la causa raíz para evitar repetición. En la Mesa de Ayuda debe quedar claro si se trata de contención, corrección, acción correctiva, preventiva o mejora.', ARRAY['acción correctiva','acción','calidad','diferencia'], 'Enseñar diferencias de gestión de calidad.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0261', 'Proceso de calidad', 'diferenciar_acciones_calidad', '¿Qué diferencia hay entre acción preventiva y otras acciones?', 'Acción preventiva: Reduce un riesgo antes de que se convierta en problema. En la Mesa de Ayuda debe quedar claro si se trata de contención, corrección, acción correctiva, preventiva o mejora.', ARRAY['acción preventiva','acción','calidad','diferencia'], 'Enseñar diferencias de gestión de calidad.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0262', 'Proceso de calidad', 'diferenciar_acciones_calidad', '¿Qué diferencia hay entre plan de mejora y otras acciones?', 'Plan de mejora: Aumenta desempeño, control o eficiencia de un proceso. En la Mesa de Ayuda debe quedar claro si se trata de contención, corrección, acción correctiva, preventiva o mejora.', ARRAY['plan de mejora','acción','calidad','diferencia'], 'Enseñar diferencias de gestión de calidad.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0263', 'Proceso de calidad', 'diferenciar_acciones_calidad', '¿Qué diferencia hay entre contención y otras acciones?', 'Contención: Controla temporalmente el impacto mientras se define solución de fondo. En la Mesa de Ayuda debe quedar claro si se trata de contención, corrección, acción correctiva, preventiva o mejora.', ARRAY['contención','acción','calidad','diferencia'], 'Enseñar diferencias de gestión de calidad.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0264', 'Conversaciones normales', 'tono_humano', 'Necesito una respuesta más humana', 'Claro. Puedo responder de forma más cercana, pero manteniendo datos verificables y trazabilidad del proceso.', ARRAY['necesito','respuesta','humana','claro','responder','forma','cercana','pero','manteniendo','datos'], 'Entrenar empatía sin perder precisión.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0265', 'Conversaciones normales', 'tono_humano', 'Háblame menos técnico', 'Entendido. Te lo explico en palabras simples y con pasos concretos.', ARRAY['háblame','menos','técnico','entendido','explico','palabras','simples','pasos','concretos'], 'Entrenar empatía sin perder precisión.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0266', 'Conversaciones normales', 'tono_humano', 'Dame una respuesta para copiar y pegar', 'Puedo proponerte una respuesta lista para usar. Debes revisarla antes de enviarla si contiene datos del ticket.', ARRAY['dame','respuesta','copiar','pegar','proponerte','lista','usar','debes','revisarla','antes'], 'Entrenar empatía sin perder precisión.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0267', 'Conversaciones normales', 'tono_humano', 'Dime la mejor opción', 'Puedo recomendar una opción con base en el proceso, pero la decisión final depende del responsable autorizado.', ARRAY['dime','mejor','opción','recomendar','base','proceso','pero','decisión','final','depende'], 'Entrenar empatía sin perder precisión.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0268', 'Conversaciones normales', 'tono_humano', 'No quiero llenar tantos campos', 'Entiendo, pero los campos mínimos evitan reprocesos y ayudan a que el caso tenga trazabilidad y respuesta correcta.', ARRAY['quiero','llenar','tantos','campos','entiendo','pero','mínimos','evitan','reprocesos','ayudan'], 'Entrenar empatía sin perder precisión.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0269', 'Conversaciones normales', 'tono_humano', 'Esto me parece muy lento', 'Podemos revisar tiempos, último seguimiento y responsable. Si hay vencimiento o bloqueo, se registra y se escala con justificación.', ARRAY['parece','lento','podemos','revisar','tiempos','último','seguimiento','responsable','vencimiento','bloqueo'], 'Entrenar empatía sin perder precisión.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0270', 'Conversaciones normales', 'tono_humano', 'Explícame como si fuera nuevo', 'Claro. La Mesa de Ayuda registra solicitudes, asigna responsables, guarda evidencias, controla estados y permite seguimiento hasta el cierre.', ARRAY['explícame','fuera','nuevo','claro','mesa','ayuda','registra','asigna','responsables','guarda'], 'Entrenar empatía sin perder precisión.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0271', 'Roles y permisos', 'explicar_rol', '¿Qué puede hacer el solicitante?', 'El rol de solicitante puede crear solicitudes, aportar información, adjuntar evidencia y consultar el avance permitido. La acción exacta depende de los permisos configurados en la aplicación.', ARRAY['solicitante','rol','permiso'], 'Entrenar explicación de roles sin prometer permisos no configurados.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0272', 'Roles y permisos', 'validar_permiso', 'Soy solicitante, ¿puedo cerrar un ticket?', 'Depende de los permisos configurados y del estado del ticket. Debes validar si el rol de solicitante tiene autorización para cierre y si el caso cumple evidencia y respuesta final.', ARRAY['solicitante','cerrar','permiso'], 'No asumir permisos; validar configuración.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0273', 'Roles y permisos', 'explicar_rol', '¿Qué puede hacer el analista de calidad?', 'El rol de analista de calidad puede revisar casos asignados, solicitar evidencia, responder seguimientos y proponer acciones. La acción exacta depende de los permisos configurados en la aplicación.', ARRAY['analista de calidad','rol','permiso'], 'Entrenar explicación de roles sin prometer permisos no configurados.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0274', 'Roles y permisos', 'validar_permiso', 'Soy analista de calidad, ¿puedo cerrar un ticket?', 'Depende de los permisos configurados y del estado del ticket. Debes validar si el rol de analista de calidad tiene autorización para cierre y si el caso cumple evidencia y respuesta final.', ARRAY['analista de calidad','cerrar','permiso'], 'No asumir permisos; validar configuración.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0275', 'Roles y permisos', 'explicar_rol', '¿Qué puede hacer el jefe general?', 'El rol de jefe general puede revisar prioridades, desbloquear casos, escalar decisiones y validar cierres según permisos. La acción exacta depende de los permisos configurados en la aplicación.', ARRAY['jefe general','rol','permiso'], 'Entrenar explicación de roles sin prometer permisos no configurados.', 'active') on conflict (id) do nothing;
