insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0277', 'Roles y permisos', 'explicar_rol', '¿Qué puede hacer el super admin?', 'El rol de super admin puede administrar usuarios, reglas, conocimientos, aprendizajes y configuración general. La acción exacta depende de los permisos configurados en la aplicación.', ARRAY['super admin','rol','permiso'], 'Entrenar explicación de roles sin prometer permisos no configurados.', 'active') on conflict (id) do nothing;
