insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0279', 'Roles y permisos', 'explicar_rol', '¿Qué puede hacer el auditoría?', 'El rol de auditoría puede revisar trazabilidad, evidencias, cumplimiento y coherencia del cierre. La acción exacta depende de los permisos configurados en la aplicación.', ARRAY['auditoría','rol','permiso'], 'Entrenar explicación de roles sin prometer permisos no configurados.', 'active') on conflict (id) do nothing;
