insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0281', 'Conversaciones normales', 'fallback_controlado', 'No encuentro ese ticket', 'No encontré el ticket con la información disponible. Verifica el código o dame otro dato como asunto, solicitante, área o fecha aproximada.', ARRAY['encuentro','encontré','información','disponible','verifica','código','dame','otro','dato','asunto'], 'Responder con precisión cuando no hay datos suficientes.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0282', 'Conversaciones normales', 'fallback_controlado', 'No tengo permiso para ver ese caso', 'No puedo mostrar información de un caso sin permiso. Puedes solicitar acceso al responsable o al administrador autorizado.', ARRAY['permiso','mostrar','información','puedes','solicitar','acceso','responsable','administrador','autorizado'], 'Responder con precisión cuando no hay datos suficientes.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0283', 'Conversaciones normales', 'fallback_controlado', 'La información está incompleta', 'La información disponible no permite dar una respuesta segura. Falta al menos un dato clave para continuar.', ARRAY['información','está','incompleta','disponible','permite','respuesta','segura','falta','menos','dato'], 'Responder con precisión cuando no hay datos suficientes.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0284', 'Conversaciones normales', 'fallback_controlado', 'Hay varias coincidencias', 'Encontré más de un posible resultado. Necesito que confirmes número de ticket, área o fecha para evitar errores.', ARRAY['varias','coincidencias','encontré','posible','resultado','necesito','confirmes','número','fecha','evitar'], 'Responder con precisión cuando no hay datos suficientes.', 'active') on conflict (id) do nothing;
insert into dt_ai_training_conversations (id, category, intent, user_message, assistant_message, keywords, learning_rule, status) values ('conv_0285', 'Conversaciones normales', 'fallback_controlado', 'No existe regla oficial', 'No encontré una regla oficial para ese caso. Puedo registrarlo como pregunta sin respuesta para revisión del Super Admin.', ARRAY['existe','regla','oficial','encontré','registrarlo','pregunta','respuesta','revisión','super','admin'], 'Responder con precisión cuando no hay datos suficientes.', 'active') on conflict (id) do nothing;
